import { execSync } from "child_process";
import { promises as fs } from "fs";
import path from "path";

async function setupVitePress() {
  const docsDir = "/home/bootstrap-v15/bootstrap/docs";

  try {
    // Check if docs exist
    const stats = await fs.stat(docsDir);
    if (!stats.isDirectory()) {
      throw new Error("Docs directory not found");
    }

    console.log("Setting up VitePress...");

    // Install dependencies
    execSync("npm add -D vitepress", { cwd: docsDir, stdio: "inherit" });
    execSync("npm add -D markdown-it-container", { cwd: docsDir, stdio: "inherit" });

    console.log("VitePress setup complete!");
    console.log("Next steps:");
    console.log("  cd docs");
    console.log("  npx vitepress dev");

    return { success: true };
  } catch (error: any) {
    console.error("Setup failed:", error.message);
    return { success: false, error: error.message };
  }
}

setupVitePress();
